// PII masking implementation
function maskPII(record) {
  const r = {...record};
  if (r.email) r.email = r.email.replace(/(.{2}).*(@.*)/, '$1***$2');
  if (r.phone) r.phone = r.phone.replace(/(\d{3})\d{4}(\d{4})/, '$1****$2');
  return r;
}
```

