## Code Example
```javascript
// Pseudo: demonstrate a simple upsert-like merge
function upsert(target, source) {
  source.forEach(s => {
    const i = target.findIndex(t => t.id === s.id);
    if (i >= 0) target[i] = { ...target[i], ...s };
    else target.push(s);
  });
  return target;
}
```

